import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Comprar.css';

const Comprar = () => {
  const [productos, setProductos] = useState([]);
  const [ingredientes, setIngredientes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [customization, setCustomization] = useState({
    extras: [],
    notes: ''
  });
  const navigate = useNavigate();

  // Obtener productos e ingredientes al cargar el componente
  useEffect(() => {
    const fetchData = async () => {
      try {
        // Obtener productos
        const productosResponse = await fetch('http://localhost:8000/api/producto', {
          headers: {
            'Content-Type': 'application/json',
            'Accept': 'application/json'
          }
        });
        
        if (!productosResponse.ok) throw new Error('Error al cargar productos');
        const productosData = await productosResponse.json();
        setProductos(productosData);

        // Obtener ingredientes
        const ingredientesResponse = await fetch('http://localhost:8000/api/ingrediente', {
          headers: {
            'Content-Type': 'application/json',
            'Accept': 'application/json'
          }
        });
        
        if (!ingredientesResponse.ok) throw new Error('Error al cargar ingredientes');
        const ingredientesData = await ingredientesResponse.json();
        setIngredientes(ingredientesData);

      } catch (err) {
        setError(err.message);
        console.error('Error:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  // Manejar selección de producto
  const handleProductSelect = (producto) => {
    setSelectedProduct(producto);
  };

  // Manejar cambios en personalización
  const handleCustomizationChange = (e) => {
    const { name, value, checked } = e.target;
    
    if (name === 'extras') {
      setCustomization(prev => {
        const newExtras = checked 
          ? [...prev.extras, value]
          : prev.extras.filter(extra => extra !== value);
        return { ...prev, extras: newExtras };
      });
    } else {
      setCustomization(prev => ({ ...prev, [name]: value }));
    }
  };

  // Manejar agregar al carrito
  const handleAddToCart = () => {
    if (!selectedProduct) return;
    
    const cartItem = {
      producto: selectedProduct,
      customization,
      quantity: 1
    };
    
    // Aquí deberías implementar la lógica para agregar al carrito
    console.log('Agregado al carrito:', cartItem);
    alert(`${selectedProduct.Nombre} agregado al carrito!`);
    
    // Resetear selección
    setSelectedProduct(null);
    setCustomization({ extras: [], notes: '' });
  };

  // Manejar ir al carrito
  const handleGoToCart = () => {
    navigate('/carrito');
  };

  if (loading) return (
    <div className="loading-container">
      <div className="spinner"></div>
      <p>Cargando productos...</p>
    </div>
  );

  if (error) return (
    <div className="error-container">
      <p>Error: {error}</p>
      <button onClick={() => window.location.reload()}>Reintentar</button>
    </div>
  );

  return (
    <div className="comprar-container">
      <h1>Nuestros Productos</h1>
      
      {/* Lista de productos */}
      <div className="productos-grid">
        {productos.map(producto => (
          <div 
            key={producto.Id} 
            className={`producto-card ${selectedProduct?.Id === producto.Id ? 'selected' : ''}`}
            onClick={() => handleProductSelect(producto)}
          >
            <h3>{producto.Nombre}</h3>
            <p>{producto.Descripcion}</p>
            <p className="price">${producto.Precio.toLocaleString()}</p>
            <p>Tamaño: {producto.Tamaño}ml</p>
            <p>Calorías: {producto.Calorias}</p>
          </div>
        ))}
      </div>

      {/* Panel de personalización */}
      {selectedProduct && (
        <div className="customization-panel">
          <h2>Personaliza tu {selectedProduct.Nombre}</h2>
          
          <div className="extras-section">
            <h3>Ingredientes Adicionales</h3>
            {ingredientes.map(ingrediente => (
              <label key={ingrediente.Id} className="extra-option">
                <input
                  type="checkbox"
                  name="extras"
                  value={ingrediente.Nombre}
                  checked={customization.extras.includes(ingrediente.Nombre)}
                  onChange={handleCustomizationChange}
                />
                {ingrediente.Nombre} (+${/* Aquí deberías tener el precio de los extras */})
              </label>
            ))}
          </div>

          <div className="notes-section">
            <h3>Notas Especiales</h3>
            <textarea
              name="notes"
              value={customization.notes}
              onChange={handleCustomizationChange}
              placeholder="Alguna indicación especial para tu pedido..."
            />
          </div>

          <div className="action-buttons">
            <button onClick={() => setSelectedProduct(null)}>Cancelar</button>
            <button onClick={handleAddToCart}>Agregar al Carrito</button>
          </div>
        </div>
      )}

      {/* Botón para ir al carrito */}
      <div className="cart-button-container">
        <button onClick={handleGoToCart} className="go-to-cart-btn">
          Ver Carrito 🛒
        </button>
      </div>
    </div>
  );
};

export default Comprar;
